import numpy as np

class Adagrad:
    def __init__(self, lr: float = 0.01, eps: float = 1e-8):
        self.lr = lr
        self.eps = eps
        self.G = None

    def step(self, params: list[np.ndarray], grads: list[np.ndarray]) -> None:
        if self.G is None:
            self.G = [np.zeros_like(p) for p in params]
        for G, p, g in zip(self.G, params, grads):
            G += g ** 2
            p -= (self.lr / (np.sqrt(G) + self.eps)) * g
